/* ============================================================
 * Helper: write embedded bytes to temp file
 * ============================================================ */
static int write_temp_onnx(const char* name, const unsigned char* data, size_t len,
                           char* out_path, size_t path_sz) {
    snprintf(out_path, path_sz, "%s", name);
    FILE* fp = fopen(out_path, "wb");
    if (!fp) return -1;
    size_t w = fwrite(data, 1, len, fp);
    fclose(fp);
    return (w == len) ? 0 : -1;
}

static void remove_temp_file(const char* path) {
    remove(path);
}

/* ============================================================
 * Protobuf parser unit tests
 * ============================================================ */

void test_varint_decode_single_byte(void) {
    const uint8_t data[] = {0x01};  /* value = 1 */
    pb_message_t* msg = pb_parse_message(data, 1, 5);
    TEST_ASSERT_NOT_NULL(msg);
    TEST_ASSERT_EQUAL(0, msg->count);  /* field 0 → no fields, varint has fn=0 */
    pb_message_destroy(msg);
}

void test_varint_decode_two_bytes(void) {
    /* field 1, wire type 0, value 150 (tag=0x08, value=0x96 0x01) */
    const uint8_t data[] = {0x08, 0x96, 0x01};
    pb_message_t* msg = pb_parse_message(data, sizeof(data), 5);
    TEST_ASSERT_NOT_NULL(msg);
    TEST_ASSERT_EQUAL(1, msg->count);
    TEST_ASSERT_EQUAL(1, msg->fields[0].field_number);
    TEST_ASSERT_EQUAL(150, (int)msg->fields[0].varint_value);
    pb_message_destroy(msg);
}

void test_varint_decode_max(void) {
    /* field 1, wire type 0, value 0xFFFFFFFFFFFFFFFF (10 bytes of 0xFF then 0x01) */
    const uint8_t data[] = {0x08, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF,
                             0xFF, 0xFF, 0xFF, 0xFF, 0x01};
    pb_message_t* msg = pb_parse_message(data, sizeof(data), 5);
    TEST_ASSERT_NOT_NULL(msg);
    TEST_ASSERT_EQUAL(1, msg->count);
    TEST_ASSERT_EQUAL(1, msg->fields[0].field_number);
    pb_message_destroy(msg);
}

void test_length_delimited_string(void) {
    /* field 1 (tag=0x0A), len=5, "hello" */
    const uint8_t data[] = {0x0A, 0x05, 'h', 'e', 'l', 'l', 'o'};
    pb_message_t* msg = pb_parse_message(data, sizeof(data), 5);
    TEST_ASSERT_NOT_NULL(msg);
    TEST_ASSERT_EQUAL(1, msg->count);
    TEST_ASSERT_EQUAL(1, msg->fields[0].field_number);
    TEST_ASSERT_EQUAL(PB_WIRE_LENGTH_DELIMITED, msg->fields[0].wire_type);
    TEST_ASSERT_EQUAL(5, (int)msg->fields[0].length_delimited.size);
    TEST_ASSERT_EQUAL('h', msg->fields[0].length_delimited.data[0]);
    TEST_ASSERT_EQUAL('o', msg->fields[0].length_delimited.data[4]);
    pb_message_destroy(msg);
}

void test_nested_message(void) {
    /* Outer message:
       field 1 (length-delimited) containing:
         field 2 (varint, value=42)
       = 0x0A 0x02  0x10 0x2A
    */
    const uint8_t data[] = {0x0A, 0x02, 0x10, 0x2A};
    pb_message_t* msg = pb_parse_message(data, sizeof(data), 5);
    TEST_ASSERT_NOT_NULL(msg);
    TEST_ASSERT_EQUAL(1, msg->count);
    TEST_ASSERT_EQUAL(1, msg->fields[0].field_number);

    pb_message_t* inner = pb_field_as_message(&msg->fields[0], 4);
    TEST_ASSERT_NOT_NULL(inner);
    TEST_ASSERT_EQUAL(1, inner->count);
    TEST_ASSERT_EQUAL(2, inner->fields[0].field_number);
    TEST_ASSERT_EQUAL(42, (int)inner->fields[0].varint_value);
    pb_message_destroy(inner);
    pb_message_destroy(msg);
}

void test_multiple_fields(void) {
    /* field 1 varint=10, field 2 varint=20, field 3 varint=30 */
    const uint8_t data[] = {0x08, 0x0A, 0x10, 0x14, 0x18, 0x1E};
    pb_message_t* msg = pb_parse_message(data, sizeof(data), 5);
    TEST_ASSERT_NOT_NULL(msg);
    TEST_ASSERT_EQUAL(3, msg->count);
    TEST_ASSERT_EQUAL(1, msg->fields[0].field_number);
    TEST_ASSERT_EQUAL(10, (int)msg->fields[0].varint_value);
    TEST_ASSERT_EQUAL(2, msg->fields[1].field_number);
    TEST_ASSERT_EQUAL(20, (int)msg->fields[1].varint_value);
    TEST_ASSERT_EQUAL(3, msg->fields[2].field_number);
    TEST_ASSERT_EQUAL(30, (int)msg->fields[2].varint_value);
    pb_message_destroy(msg);
}

void test_pb_find_field(void) {
    const uint8_t data[] = {0x08, 0x0A, 0x10, 0x14, 0x18, 0x1E};
    pb_message_t* msg = pb_parse_message(data, sizeof(data), 5);
    pb_field_t* f = pb_find_field(msg, 2);
    TEST_ASSERT_NOT_NULL(f);
    TEST_ASSERT_EQUAL(20, (int)f->varint_value);
    f = pb_find_field(msg, 99);
    TEST_ASSERT_NULL(f);
    pb_message_destroy(msg);
}

void test_pb_find_all_fields(void) {
    /* field 1 varint=10, field 2 varint=20, field 1 varint=30 */
    const uint8_t data[] = {0x08, 0x0A, 0x10, 0x14, 0x08, 0x1E};
    pb_message_t* msg = pb_parse_message(data, sizeof(data), 5);
    pb_field_t** arr = NULL;
    int cnt = 0;
    int rc = pb_find_all_fields(msg, 1, &arr, &cnt);
    TEST_ASSERT_EQUAL(0, rc);
    TEST_ASSERT_EQUAL(2, cnt);
    TEST_ASSERT_EQUAL(10, (int)arr[0]->varint_value);
    TEST_ASSERT_EQUAL(30, (int)arr[1]->varint_value);
    free(arr);
    pb_message_destroy(msg);
}

void test_pb_field_get_int64(void) {
    const uint8_t data[] = {0x08, 0x96, 0x01, 0x10, 0x14};
    pb_message_t* msg = pb_parse_message(data, sizeof(data), 5);
    TEST_ASSERT_EQUAL(150, (int)pb_field_get_int64(msg, 1, 0));
    TEST_ASSERT_EQUAL(20, (int)pb_field_get_int64(msg, 2, 0));
    TEST_ASSERT_EQUAL(99, (int)pb_field_get_int64(msg, 99, 99));  /* default */
    pb_message_destroy(msg);
}

void test_pb_field_get_string(void) {
    const uint8_t data[] = {0x0A, 0x04, 't', 'e', 's', 't'};
    pb_message_t* msg = pb_parse_message(data, sizeof(data), 5);
    size_t slen = 0;
    const uint8_t* s = pb_field_get_string(msg, 1, &slen);
    TEST_ASSERT_NOT_NULL(s);
    TEST_ASSERT_EQUAL(4, (int)slen);
    TEST_ASSERT_EQUAL('t', s[0]);
    TEST_ASSERT_EQUAL('t', s[3]);
    pb_message_destroy(msg);
}

void test_decode_packed_varints(void) {
    /* Packed: [1, 2, 3, 4] as LEB128 bytes */
    const uint8_t data[] = {0x01, 0x02, 0x03, 0x04};
    int64_t vals[8];
    int cnt = 0;
    int rc = pb_decode_packed_varints(data, sizeof(data), vals, 8, &cnt);
    TEST_ASSERT_EQUAL(0, rc);
    TEST_ASSERT_EQUAL(4, cnt);
    TEST_ASSERT_EQUAL(1, (int)vals[0]);
    TEST_ASSERT_EQUAL(4, (int)vals[3]);
}

void test_decode_float_data(void) {
    /* 1.0f, 2.0f as little-endian bytes */
    float f1 = 1.0f, f2 = 2.0f;
    uint8_t data[8];
    memcpy(data, &f1, 4);
    memcpy(data + 4, &f2, 4);
    float vals[4];
    int cnt = 0;
    int rc = pb_decode_float_data(data, sizeof(data), vals, 4, &cnt);
    TEST_ASSERT_EQUAL(0, rc);
    TEST_ASSERT_EQUAL(2, cnt);
    TEST_ASSERT_FLOAT_WITHIN(0.001f, 1.0f, vals[0]);
    TEST_ASSERT_FLOAT_WITHIN(0.001f, 2.0f, vals[1]);
}

void test_empty_message(void) {
    pb_message_t* msg = pb_parse_message(NULL, 0, 5);
    TEST_ASSERT_NOT_NULL(msg);
    TEST_ASSERT_EQUAL(0, msg->count);
    pb_message_destroy(msg);
}

void test_truncated_varint(void) {
    /* Truncated: tag byte 0x08 starts varint field 1, but nothing follows */
    const uint8_t data[] = {0x08};
    pb_message_t* msg = pb_parse_message(data, sizeof(data), 5);
    /* Should fail on truncated varint value */
    TEST_ASSERT_NOT_NULL(msg);
    TEST_ASSERT_EQUAL(0, msg->count);
    pb_message_destroy(msg);
}

void test_max_depth_exceeded(void) {
    /* Nested: field 1 containing field 1 containing ... */
    const uint8_t data[] = {0x0A, 0x02, 0x0A, 0x00};
    pb_message_t* msg = pb_parse_message(data, sizeof(data), 1);
    TEST_ASSERT_NOT_NULL(msg);
    /* Inner nested parse called from pb_parse_message with max_depth=1
       won't parse deeper than depth 1 */
    pb_message_destroy(msg);

    pb_message_t* msg2 = pb_parse_message(data, sizeof(data), 0);
    TEST_ASSERT_NULL(msg2);
}

void test_pb_field_as_message_null(void) {
    pb_message_t* m = pb_field_as_message(NULL, 1);
    TEST_ASSERT_NULL(m);
}

void test_pb_find_all_fields_empty(void) {
    pb_field_t** arr = NULL;
    int cnt = 0;
    int rc = pb_find_all_fields(NULL, 1, &arr, &cnt);
    TEST_ASSERT_EQUAL(-1, rc);
    TEST_ASSERT_EQUAL(0, cnt);
    TEST_ASSERT_NULL(arr);
}

void test_pb_message_destroy_null(void) {
    pb_message_destroy(NULL);  /* should not crash */
}

