/* ============================================================
 * Integration test: ReLU model (CPU)
 * ============================================================ */
void test_relu_model_cpu(void) {
    char path[512];
    int rc = write_temp_onnx("test_relu_cpu.onnx",
                              onnx_test_relu_data, onnx_test_relu_data_len,
                              path, sizeof(path));
    TEST_ASSERT_EQUAL(0, rc);

    inference_session_t* session = inference_session_load(path);
    TEST_ASSERT_NOT_NULL(session);
    remove_temp_file(path);

    TEST_ASSERT_EQUAL(1, inference_session_num_inputs(session));
    TEST_ASSERT_EQUAL(1, inference_session_num_outputs(session));

    /* Create input: [-1, 0, 2, -3] */
    int64_t shape[] = {1, 4};
    tensor_t* input = tensor_create(DATA_TYPE_F32, 2, shape);
    float* idata = (float*)input->data;
    idata[0] = -1.0f; idata[1] = 0.0f; idata[2] = 2.0f; idata[3] = -3.0f;

    tensor_t* input_arr[] = {input};
    tensor_t* output = tensor_create(DATA_TYPE_F32, 2, shape);
    tensor_t* output_arr[] = {output};

    rc = inference_session_run(session, input_arr, output_arr, 0);  /* CPU */
    TEST_ASSERT_EQUAL(0, rc);

    float* odata = (float*)output->data;
    /* ReLU: [-1,0,2,-3] -> [0,0,2,0] */
    TEST_ASSERT_FLOAT_WITHIN(0.001f, 0.0f, odata[0]);
    TEST_ASSERT_FLOAT_WITHIN(0.001f, 0.0f, odata[1]);
    TEST_ASSERT_FLOAT_WITHIN(0.001f, 2.0f, odata[2]);
    TEST_ASSERT_FLOAT_WITHIN(0.001f, 0.0f, odata[3]);

    tensor_destroy(input);
    tensor_destroy(output);
    inference_session_destroy(session);
}

/* ============================================================
 * Integration test: Chain model (ReLU → ReLU) CPU
 * ============================================================ */
void test_chain_model_cpu(void) {
    char path[512];
    int rc = write_temp_onnx("test_chain_cpu.onnx",
                              onnx_test_chain_data, onnx_test_chain_data_len,
                              path, sizeof(path));
    TEST_ASSERT_EQUAL(0, rc);

    inference_session_t* session = inference_session_load(path);
    TEST_ASSERT_NOT_NULL(session);
    remove_temp_file(path);

    int64_t shape[] = {1, 4};
    tensor_t* input = tensor_create(DATA_TYPE_F32, 2, shape);
    float* idata = (float*)input->data;
    idata[0] = -1.0f; idata[1] = 0.0f; idata[2] = 2.0f; idata[3] = -3.0f;

    tensor_t* input_arr[] = {input};
    tensor_t* output = tensor_create(DATA_TYPE_F32, 2, shape);
    tensor_t* output_arr[] = {output};

    rc = inference_session_run(session, input_arr, output_arr, 0);
    TEST_ASSERT_EQUAL(0, rc);

    float* odata = (float*)output->data;
    /* ReLU(ReLU(x)) == ReLU(x): [-1,0,2,-3] -> [0,0,2,0] */
    TEST_ASSERT_FLOAT_WITHIN(0.001f, 0.0f, odata[0]);
    TEST_ASSERT_FLOAT_WITHIN(0.001f, 0.0f, odata[1]);
    TEST_ASSERT_FLOAT_WITHIN(0.001f, 2.0f, odata[2]);
    TEST_ASSERT_FLOAT_WITHIN(0.001f, 0.0f, odata[3]);

    tensor_destroy(input);
    tensor_destroy(output);
    inference_session_destroy(session);
}

